import{_ as a,o as e,c as l,a2 as i}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"国家赔偿公司（National Indemnity Company）","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/国家赔偿公司.md","filePath":"03_companies/国家赔偿公司.md"}'),r={name:"03_companies/国家赔偿公司.md"};function d(o,t,h,n,s,u){return e(),l("div",null,[...t[0]||(t[0]=[i('<h1 id="国家赔偿公司-national-indemnity-company" tabindex="-1">国家赔偿公司（National Indemnity Company） <a class="header-anchor" href="#国家赔偿公司-national-indemnity-company" aria-label="Permalink to &quot;国家赔偿公司（National Indemnity Company）&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>属性</th><th>内容</th></tr></thead><tbody><tr><td>英文名</td><td>National Indemnity Company</td></tr><tr><td>行业</td><td>财产意外保险</td></tr><tr><td>成立年份</td><td>1940年</td></tr><tr><td>总部</td><td>内布拉斯加州奥马哈</td></tr><tr><td>伯克希尔持股</td><td>100%（1967年收购）</td></tr></tbody></table><h2 id="核心业务" tabindex="-1">核心业务 <a class="header-anchor" href="#核心业务" aria-label="Permalink to &quot;核心业务&quot;">​</a></h2><p>专业意外险和汽车保险，包括：</p><ul><li>商业汽车责任险</li><li>一般责任险</li><li>工人补偿险（通过子公司）</li><li>再保险业务</li></ul><h2 id="收购故事" tabindex="-1">收购故事 <a class="header-anchor" href="#收购故事" aria-label="Permalink to &quot;收购故事&quot;">​</a></h2><h3 id="_1967年收购" tabindex="-1">1967年收购 <a class="header-anchor" href="#_1967年收购" aria-label="Permalink to &quot;1967年收购&quot;">​</a></h3><ul><li>巴菲特以860万美元收购国家赔偿公司</li><li>这是伯克希尔从纺织转型保险的关键一步</li><li>创始人杰克·林格沃特保留了承保纪律</li></ul><h3 id="收购逻辑" tabindex="-1">收购逻辑 <a class="header-anchor" href="#收购逻辑" aria-label="Permalink to &quot;收购逻辑&quot;">​</a></h3><ol><li><strong>保险浮存金</strong>：先收保费后理赔，提供免费杠杆</li><li><strong>承保纪律</strong>：创始人建立了严格文化</li><li><strong>管理延续</strong>：杰克·林格沃特继续管理</li></ol><h2 id="核心竞争优势" tabindex="-1">核心竞争优势 <a class="header-anchor" href="#核心竞争优势" aria-label="Permalink to &quot;核心竞争优势&quot;">​</a></h2><h3 id="_1-承保纪律" tabindex="-1">1. 承保纪律 <a class="header-anchor" href="#_1-承保纪律" aria-label="Permalink to &quot;1. 承保纪律&quot;">​</a></h3><ul><li>只做价格合适的业务</li><li>不惜大幅缩减业务量保持盈利</li><li>这种纪律代代传承</li></ul><h3 id="_2-浮存金价值" tabindex="-1">2. 浮存金价值 <a class="header-anchor" href="#_2-浮存金价值" aria-label="Permalink to &quot;2. 浮存金价值&quot;">​</a></h3><ul><li>保险浮存金用于伯克希尔投资</li><li>低成本甚至负成本的杠杆</li><li>伯克希尔增长的根基</li></ul><h3 id="_3-再保险能力" tabindex="-1">3. 再保险能力 <a class="header-anchor" href="#_3-再保险能力" aria-label="Permalink to &quot;3. 再保险能力&quot;">​</a></h3><ul><li>承接其他保险公司不敢接的风险</li><li>定价能力强</li><li>长期资本优势</li></ul><h2 id="管理团队" tabindex="-1">管理团队 <a class="header-anchor" href="#管理团队" aria-label="Permalink to &quot;管理团队&quot;">​</a></h2><h3 id="关键人物" tabindex="-1">关键人物 <a class="header-anchor" href="#关键人物" aria-label="Permalink to &quot;关键人物&quot;">​</a></h3><table tabindex="0"><thead><tr><th>姓名</th><th>职位</th><th>贡献</th></tr></thead><tbody><tr><td>杰克·林格沃特</td><td>创始人</td><td>建立承保纪律文化</td></tr><tr><td><a href="./../04_人物库/菲尔·利切.html">菲尔·利切</a></td><td>总裁</td><td>1982年退休，管理出色</td></tr><tr><td>罗兰·米勒</td><td>核保</td><td>杰出协助</td></tr><tr><td>比尔·莱昂斯</td><td>理赔</td><td>杰出协助</td></tr></tbody></table><h2 id="巴菲特评价摘录" tabindex="-1">巴菲特评价摘录 <a class="header-anchor" href="#巴菲特评价摘录" aria-label="Permalink to &quot;巴菲特评价摘录&quot;">​</a></h2><blockquote><p>&quot;国家赔偿公司一直是伯克希尔增长最重要的运营。&quot; —— 1978年股东信</p></blockquote><blockquote><p>&quot;杰克·林格沃特的经营哲学至今深刻烙印在公司。&quot; —— 1978年股东信</p></blockquote><blockquote><p>&quot;菲尔·利切每一分保费都带着自己拥有企业一样的关心和干劲处理。&quot; —— 1982年股东信</p></blockquote><h2 id="财务表现-摘录" tabindex="-1">财务表现（摘录） <a class="header-anchor" href="#财务表现-摘录" aria-label="Permalink to &quot;财务表现（摘录）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>承保利润</th><th>备注</th></tr></thead><tbody><tr><td>1978</td><td>约1,100万美元</td><td>非凡成就</td></tr><tr><td>1981</td><td>约1,100万美元</td><td>行业领先</td></tr></tbody></table><h2 id="在股东信中的年份" tabindex="-1">在股东信中的年份 <a class="header-anchor" href="#在股东信中的年份" aria-label="Permalink to &quot;在股东信中的年份&quot;">​</a></h2><p>1977, 1978, 1979, 1980, 1981, 1982, 1983, 1984, 1985, 1986, 1987</p><h2 id="相关链接" tabindex="-1">相关链接 <a class="header-anchor" href="#相关链接" aria-label="Permalink to &quot;相关链接&quot;">​</a></h2><ul><li><a href="./GEICO.html">GEICO</a> - 同为保险核心</li><li><a href="./../04_人物库/菲尔·利切.html">菲尔·利切</a> - 总裁</li><li><a href="./../02_主题索引/投资哲学/保险浮存金.html">保险浮存金</a> - 核心价值</li></ul><hr><p><em>最后更新：2026-04-09</em></p><h2 id="相关信件" tabindex="-1">相关信件 <a class="header-anchor" href="#相关信件" aria-label="Permalink to &quot;相关信件&quot;">​</a></h2><ul><li><a href="./../01_letters/1995年/翻译.html">1995年</a></li><li><a href="./../01_letters/2004年/翻译.html">2004年</a></li><li><a href="./../01_letters/2006年/翻译.html">2006年</a></li><li><a href="./../01_letters/2014年/翻译.html">2014年</a></li><li><a href="./../01_letters/2020年/翻译.html">2020年</a></li><li><a href="./../01_letters/2022年/翻译.html">2022年</a></li></ul>',35)])])}const m=a(r,[["render",d]]);export{b as __pageData,m as default};
